class Chart{constructor(ctx,cfg){this.ctx=ctx.getContext("2d");this.canvas=ctx;this.cfg=cfg;this.draw()}destroy(){this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height)}draw(){const c=this.canvas,ctx=this.ctx,d=this.cfg.data||{},labels=d.labels||[],vals=(d.datasets&&d.datasets[0].data||[]).filter(v=>v!==null&&v!==undefined&&!Number.isNaN(v));const type=this.cfg.type||"line";const ratio=window.devicePixelRatio||1,w=c.clientWidth||600,h=260;c.width=w*ratio;c.height=h*ratio;ctx.scale(ratio,ratio);ctx.clearRect(0,0,w,h);ctx.font="12px Arial";ctx.fillStyle="#6b7780";ctx.strokeStyle="#d9e2e2";ctx.lineWidth=1;const pad=38;ctx.beginPath();ctx.moveTo(pad,10);ctx.lineTo(pad,h-pad);ctx.lineTo(w-10,h-pad);ctx.stroke();if(!vals.length){ctx.fillText("Sin datos todavía",pad+10,50);return}const min=Math.min(...vals),max=Math.max(...vals),range=(max-min)||1;function x(i){return pad+(i*((w-pad-20)/Math.max(1,vals.length-1)))}function y(v){return (h-pad)-((v-min)/range)*(h-pad-24)}ctx.fillStyle="#6b7780";ctx.fillText(max.toFixed(1),4,18);ctx.fillText(min.toFixed(1),4,h-pad);ctx.strokeStyle="#005357";ctx.fillStyle="#005357";ctx.lineWidth=3;if(type==="bar"){const bw=Math.max(8,(w-pad-30)/vals.length*.55);vals.forEach((v,i)=>{const xx=pad+((i+.5)*(w-pad-20)/vals.length)-bw/2;ctx.fillRect(xx,y(v),bw,h-pad-y(v));});}else{ctx.beginPath();vals.forEach((v,i)=>{if(i===0)ctx.moveTo(x(i),y(v));else ctx.lineTo(x(i),y(v));});ctx.stroke();vals.forEach((v,i)=>{ctx.beginPath();ctx.arc(x(i),y(v),4,0,Math.PI*2);ctx.fill();});}ctx.fillStyle="#1f2933";ctx.font="bold 13px Arial";ctx.fillText((d.datasets&&d.datasets[0].label)||"",pad,20);}}